import React from "react";

const Card = ({ title, description, imageUrl, onClick }) => {
  return (
    <button onClick={onClick} className="focus:outline-none w-full max-w-md">
      <div className="bg-white rounded-2xl shadow-lg overflow-hidden w-full">
        {imageUrl && (
          <img
            className="w-full h-64 object-cover"
            src={imageUrl}
            alt="Card"
          />
        )}
        <div className="p-6">
          <div className="font-bold text-2xl mb-2 text-left text-gray-900">
            {title}
          </div>
          <p className="text-gray-700 text-base text-left">{description}</p>
        </div>
      </div>
    </button>
  );
};

export default Card;
